// Java 25 exam prep - Primitive streams
// Learn: move between Stream<String>, IntStream, statistics, and boxed values.
IntSummaryStatistics stats = Arrays.asList("4", "8", "15").stream()
    .mapToInt(Integer::parseInt) // mapToInt creates an IntStream, not Stream<Integer>.
    .summaryStatistics();
List<Integer> boxed = IntStream.rangeClosed(1, 3)
    .boxed()
    .collect(Collectors.toList());
System.out.println(stats.getMax() + boxed.size());
